import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./EmployeeForm.css";

function AddEmployee() {

  const navigate = useNavigate();
  const { id } = useParams();
  const isEditMode = Boolean(id);

  const [activeTab, setActiveTab] = useState("personal");

  const [errors, setErrors] = useState({});

  const [employee, setEmployee] = useState({
    firstName:"",
    lastName:"",
    empId:"",
    gender:"",
    dob:"",
    maritalStatus:"",
    email:"",
    aadhar:"",
    pan:"",
    designation:"",
    department:"",
    salary:"",
    role:"",
    skills:[],
    tempSkill:"",
    customSkill:"",
    bankName:"",
    accountNumber:"",
    ifsc:"",
    qualification:"",
    university:"",
    passingYear:"",
    employeeFiles:[],
    certificates:[]
  });

  /* ================= LOAD EDIT DATA ================= */
  useEffect(()=>{
    if(!isEditMode) return;
    const list=JSON.parse(localStorage.getItem("employees"))||[];
    const found=list.find(e=>String(e.id)===String(id));
    if(found) setEmployee(found);
  },[id,isEditMode]);

  /* ================= INPUT CHANGE ================= */
  const handleChange=(e)=>{
    setEmployee({...employee,[e.target.name]:e.target.value});
  };

  /* ================= VALIDATIONS ================= */
  const validateFields=()=>{
    const newErr={};

    if(employee.aadhar && !/^\d{12}$/.test(employee.aadhar))
      newErr.aadhar="Aadhar must be 12 digits";

    if(employee.pan && !/^[A-Z]{5}[0-9]{4}[A-Z]{1}$/.test(employee.pan))
      newErr.pan="Invalid PAN format";

    setErrors(newErr);
    return Object.keys(newErr).length===0;
  };

  /* ================= FILE CONVERT ================= */
  const convertFiles=(files)=>(
    Array.from(files).map(file=>({
      name:file.name,
      size:file.size,
      type:file.type,
      url:URL.createObjectURL(file)
    }))
  );

  /* ================= FILE HANDLER ================= */
  const handleUpload=(files,field)=>{
    const converted=convertFiles(files);
    setEmployee(prev=>({
      ...prev,
      [field]:[...prev[field],...converted]
    }));
  };

  /* DRAG DROP */
  const handleDrop=(e,field)=>{
    e.preventDefault();
    handleUpload(e.dataTransfer.files,field);
  };

  /* REMOVE FILE */
  const removeFile=(index,field)=>{
    const updated=[...employee[field]];
    updated.splice(index,1);
    setEmployee(prev=>({...prev,[field]:updated}));
  };

  /* ================= SAVE ================= */
  const handleSubmit=(e)=>{
    e.preventDefault();
    if(!validateFields()) return;

    let list=JSON.parse(localStorage.getItem("employees"))||[];

    if(isEditMode){
      list=list.map(emp=>String(emp.id)===String(id)?employee:emp);
    }else{
      list.push({id:Date.now(),name:`${employee.firstName} ${employee.lastName}`,...employee});
    }

    localStorage.setItem("employees",JSON.stringify(list));
    alert("Saved Successfully");
    navigate("/dashboard/employee-details");
  };

  /* ================= FILE CARD ================= */
  const FileCards=(field)=>(
    <div className="file-card-container">
      {employee[field].map((f,i)=>(
        <div key={i} className="file-card">
          <span>{f.name}</span>
          <button onClick={()=>removeFile(i,field)}>✖</button>
        </div>
      ))}
    </div>
  );

  return (
    <div className="add-employee-page">
      <h2>{isEditMode?"Edit Employee":"Add Employee"}</h2>

      <div className="tabs">
        {["personal","employment","bank","education"].map(t=>(
          <button
            key={t}
            className={`tab ${activeTab===t?"active":""}`}
            onClick={()=>setActiveTab(t)}
          >
            {t.toUpperCase()}
          </button>
        ))}
      </div>

      <form className="employee-form" onSubmit={handleSubmit}>

        {/* PERSONAL */}
        {activeTab==="personal"&&(
          <>
            <h3>Personal Details</h3>
            <div className="employee-grid">

              <input name="firstName" placeholder="First Name" value={employee.firstName} onChange={handleChange}/>
              <input name="lastName" placeholder="Last Name" value={employee.lastName} onChange={handleChange}/>
              <input name="empId" placeholder="Employee ID" value={employee.empId} onChange={handleChange}/>
              <input type="email" name="email" placeholder="Email" value={employee.email} onChange={handleChange}/>

              <input
                name="aadhar"
                placeholder="Aadhar Number"
                maxLength="12"
                value={employee.aadhar}
                onChange={handleChange}
                className={errors.aadhar?"error-input":""}
              />
              {errors.aadhar && <span className="error-text">{errors.aadhar}</span>}

              <input
                name="pan"
                placeholder="PAN"
                value={employee.pan}
                onChange={(e)=>setEmployee({...employee,pan:e.target.value.toUpperCase()})}
                className={errors.pan?"error-input":""}
              />
              {errors.pan && <span className="error-text">{errors.pan}</span>}

              {/* DRAG ZONE */}
              <div
                className="upload-zone"
                onDragOver={(e)=>e.preventDefault()}
                onDrop={(e)=>handleDrop(e,"employeeFiles")}
              >
                Drag Employee Files Here
                <input type="file" multiple onChange={(e)=>handleUpload(e.target.files,"employeeFiles")}/>
              </div>

              {FileCards("employeeFiles")}

            </div>
          </>
        )}

        {/* EDUCATION */}
        {activeTab==="education"&&(
          <>
            <h3>Certificates</h3>
            <div
              className="upload-zone"
              onDragOver={(e)=>e.preventDefault()}
              onDrop={(e)=>handleDrop(e,"certificates")}
            >
              Drag Certificates Here
              <input type="file" multiple onChange={(e)=>handleUpload(e.target.files,"certificates")}/>
            </div>

            {FileCards("certificates")}
          </>
        )}

        <button className="save-btn" type="submit">
          {isEditMode?"Update Employee":"Save Employee"}
        </button>

      </form>
    </div>
  );
}

export default AddEmployee;
